using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval — returns JsonTypeInfo<Person> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata: {personInfo.Type.Name}");

// Round-trip to prove it works
var json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized: {json}");

Person p = JsonSerializer.Deserialize(json, personInfo)!;
Console.WriteLine($"Deserialized: {p}");

// 2) Probe without throwing — TryGetTypeInfo returns false if unavailable
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
    Console.WriteLine($"TryGet succeeded for {info!.Type.Name}");

// Now try a resolver that doesn't know about UnknownType
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};
// DefaultJsonTypeInfoResolver resolves anything, so use a custom one that refuses:
limited.TypeInfoResolver = JsonTypeInfoResolver.Combine(); // empty — resolves nothing

if (limited.TryGetTypeInfo(typeof(UnknownType), out JsonTypeInfo? missing))
    Console.WriteLine("Should not reach here");
else
    Console.WriteLine("TryGet correctly returned false for UnknownType");

record Person(string Name, int Age);
record UnknownType(int X);

